// returnRow is one purchased item still inside the chosen return window.
type returnRow struct {
	TransactionDate string  `json:"transactionDate"`
	DaysAgo         int     `json:"daysAgo"`
	DaysLeft        int     `json:"daysLeft"`
	WarehouseName   string  `json:"warehouseName"`
	ItemNumber      string  `json:"itemNumber"`
	Description     string  `json:"description"`
	Amount          float64 `json:"amount"`
}

// itemsInWindow returns line items purchased within the last `days` days,
// annotated with how many days remain in the window. now is injected for
// testability. Receipts whose date cannot be parsed are skipped (not guessed).
// Costco's published return policy is generous and item-dependent; this is a
// user-set reminder window, not an authoritative eligibility ruling.
func itemsInWindow(receipts []costcoReceipt, days int, now time.Time) []returnRow {
	rows := []returnRow{}
	if days <= 0 {
		return rows
	}
	today := now.Truncate(24 * time.Hour)
	for _, r := range receipts {
		d, ok := parseReceiptDate(r.TransactionDate)
		if !ok {
			continue
		}
		ageDays := int(today.Sub(d.Truncate(24*time.Hour)).Hours() / 24)
		if ageDays < 0 || ageDays > days {
			continue
		}
		for _, it := range r.ItemArray {
			rows = append(rows, returnRow{
				TransactionDate: r.TransactionDate,
				DaysAgo:         ageDays,
				DaysLeft:        days - ageDays,
				WarehouseName:   r.WarehouseName,
				ItemNumber:      it.ItemNumber.String(),
				Description:     strings.TrimSpace(it.Description + " " + it.Description2),
				Amount:          it.Amount.float(),
			})
		}
	}
	sort.Slice(rows, func(i, j int) bool { return rows[i].DaysLeft < rows[j].DaysLeft })
	return rows
}

// parseReceiptDate parses a Costco transactionDate, accepting a bare date or a
// fuller timestamp prefixed with YYYY-MM-DD.
func parseReceiptDate(s string) (time.Time, bool) {
	s = strings.TrimSpace(s)
	if len(s) >= 10 {
		if t, err := time.Parse(dateLayout, s[:10]); err == nil {
			return t, true
		}
	}
	if t, err := time.Parse(time.RFC3339, s); err == nil {
		return t, true
	}
	return time.Time{}, false
}

